function isAnagram(a, b) {
  if (a.length !== b.length) return false;
  const freq = {};
  for (let i = 0; i < a.length; i++) freq[a[i]] = (freq[a[i]] || 0) + 1;
  for (let i = 0; i < b.length; i++) {
    if (!freq[b[i]]) return false;
    freq[b[i]]--;
  }
  return true;
}

function swapCase(s) {
  const parts = [];
  for (let i = 0; i < s.length; i++) {
    const c = s[i];
    if (c >= "a" && c <= "z") {
      parts.push(String.fromCharCode(c.charCodeAt(0) - 32));
    } else if (c >= "A" && c <= "Z") {
      parts.push(String.fromCharCode(c.charCodeAt(0) + 32));
    } else {
      parts.push(c);
    }
  }
  return parts.join("");
}

