function startsWith(s, p) {
  if (p.length > s.length) return false;
  for (let i = 0; i < p.length; i++) {
    if (s[i] !== p[i]) return false;
  }
  return true;
}

function removeVowels(s) {
  const parts = [];
  for (let i = 0; i < s.length; i++) {
    if ("aeiou".indexOf(s[i]) === -1) parts.push(s[i]);
  }
  return parts.join("");
}
